    if not work_md.is_file():
        return {}
    match = PARALLEL_LANE_SECTION_RE.search(read_text(work_md))
    if not match:
        return {}
    fields: dict[str, str] = {}
    for raw_label, raw_value in PARALLEL_LANE_FIELD_RE.findall(match.group(1)):
        fields[raw_label.strip().lower()] = raw_value.strip()
    return fields


def shared_surface_category_for_path(path: str) -> str:
    normalized = path.strip()
    if normalized.startswith("docs/roadmap/lane-imports/") and normalized.endswith(".json"):
        return "lane_import_bundle"
    if re.fullmatch(r"docs/handoffs/HANDOFF-SESSION-v[0-9]+(?:[A-Za-z]|-[A-Za-z0-9-]+)?\.md", normalized):
        return "canonical_handoff"
    if normalized in {
        "docs/roadmap/LIVE_ROADMAP.md",
        "docs/roadmap/ROADMAP_LEDGER.jsonl",
        "docs/roadmap/BOOTSTRAP_SOURCE_MANIFEST.json",
    }:
        return "canonical_roadmap"
    if normalized in {
        "schemas/roadmap-item.schema.json",
        "schemas/roadmap-lane-import.schema.json",
    }:
        return "canonical_roadmap_schema"
    if normalized == "LEARNINGS.md":
        return "learnings_surface"
    if normalized in {
        "work/PRINCIPLE_LEDGER.jsonl",
        "work/WARNING_LEDGER.jsonl",
        "work/SCORE_LEDGER.jsonl",
        "work/FLEET_REPORTS.jsonl",
        "work/NNF_LOG.md",
    }:
        return "repo_work_ledger"
    if normalized == "AGENTS.md":
        return "bootloader"
    if normalized in {"research/INDEX.md", "tests/manifest-ci.txt"}:
        return "shared_index_or_manifest"
    return ""


def build_parallel_lane_state(work_dir: Path, repo_root: Path) -> dict[str, Any]:
    fields = parse_parallel_lane_fields(work_dir)
    if not fields:
        return {
            "present": False,
            "role": "",
            "merge_path": "",
            "current_branch": current_git_branch(repo_root),
            "changed_paths_file": "",
            "changed_paths_total": 0,
            "serialized_shared_surface_paths": [],
            "lane_import_bundle_paths": [],
            "requires_reconciliation_role": False,
            "status": "not_applicable",
        }

    changed_paths_file = work_dir / ".parallel-lane-changed-paths.txt"
    serialized_paths: list[str] = []
    lane_import_paths: list[str] = []
    changed_paths_total = 0
    if changed_paths_file.is_file():
        for raw_line in read_text(changed_paths_file).splitlines():
            changed_path = raw_line.strip()
            if not changed_path:
                continue
            changed_paths_total += 1
            category = shared_surface_category_for_path(changed_path)
            if category == "lane_import_bundle":
                lane_import_paths.append(changed_path)
            elif category:
                serialized_paths.append(changed_path)

    role = fields.get("role", "")
    merge_path = fields.get("merge path", "")
    current_branch = current_git_branch(repo_root)
    requires_reconciliation_role = bool(serialized_paths)

    if serialized_paths and role == "reconciliation" and current_branch == "main":
        status = "serialized_shared_surfaces_reconciled"
    elif serialized_paths and role == "reconciliation":
        status = "serialized_shared_surfaces_off_main"
    elif serialized_paths:
        status = "serialized_shared_surfaces_without_reconciliation_role"
    elif lane_import_paths and merge_path.lower() == "lane-import only":
        status = "lane_import_only"
    else:
        status = "no_shared_surfaces"

    return {
        "present": True,
        "role": role,
        "merge_path": merge_path,
        "current_branch": current_branch,
        "changed_paths_file": relative_path(changed_paths_file, repo_root) if changed_paths_file.is_file() else "",
        "changed_paths_total": changed_paths_total,
        "serialized_shared_surface_paths": sorted(unique_strings(serialized_paths)),
        "lane_import_bundle_paths": sorted(unique_strings(lane_import_paths)),
        "requires_reconciliation_role": requires_reconciliation_role,
        "status": status,
    }


def parse_run_dirs(work_dir: Path, measurement_summary: dict[str, Any]) -> list[str]:
    candidates: list[str] = []
    work_md = work_dir / "WORK.md"
    if work_md.is_file():
        for raw_line in read_text(work_md).splitlines():
            stripped = raw_line.strip()
            if stripped.startswith(("- ", "* ")):
                stripped = stripped[2:].strip()
            stripped = stripped.strip("`")
            if RUN_DIR_LINE_RE.fullmatch(stripped):
                candidates.append(stripped.rstrip("/"))
    summary_dirs = measurement_summary.get("referenced_run_dirs", [])
    if isinstance(summary_dirs, list):
        for item in summary_dirs:
            if isinstance(item, str):
                candidates.append(item.rstrip("/"))
    return sorted(unique_strings(candidates))


def discover_run_dirs(repo_root: Path, work_dir: Path) -> list[str]:
    runs_root = repo_root / "runs"
    if not runs_root.is_dir():
        return []
    prefix = f"{work_dir.name}_"
    discovered = [
        relative_path(candidate, repo_root)
        for candidate in sorted(runs_root.iterdir())
        if candidate.is_dir() and candidate.name.startswith(prefix)
    ]
    return unique_strings(discovered)


def git_dirty_run_paths(repo_root: Path) -> list[str]:
    try:
        result = subprocess.run(
            ["git", "-C", str(repo_root), "status", "--short"],
            capture_output=True,
            text=True,
            check=False,
            timeout=10,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError):
        return []

    dirty_paths: list[str] = []
    for line in result.stdout.splitlines():
        match = RUN_DIR_RE.search(line)
        if match:
            dirty_paths.append(match.group(0).rstrip("/"))
    return sorted(unique_strings(dirty_paths))


