    prompt_text = ""
    for raw in events_path.read_text(encoding="utf-8", errors="ignore").splitlines():
        try:
            event = json.loads(raw)
        except json.JSONDecodeError:
            continue
        if event.get("type") == "user.message":
            prompt_text = str(event.get("data", {}).get("content") or "")
