def classify_root_package(
    receipt_present: bool,
    receipt_counts_as_success: bool,
    closeout_present: bool,
    closeout_ran: str,
    ser_present: bool,
    ser_ran: str,
    scorecard_present: bool,
    bm002_result: str,
) -> tuple[str, str]:
    contradictions: list[str] = []
    downstream_present = closeout_present or ser_present or scorecard_present

    if receipt_present and receipt_counts_as_success:
        if closeout_present and closeout_ran != "true":
            contradictions.append("closeout")
        if ser_present and ser_ran != "true":
            contradictions.append("ser")
        if scorecard_present and bm002_result != "PASS":
            contradictions.append("scorecard")
        if contradictions:
            return "consumer_drift", ",".join(contradictions)
        if downstream_present:
            return "aligned_success", "success receipt agrees with downstream surfaces"
        return "root_success_without_downstream", "root receipt present but no downstream surface retained"

    if receipt_present and not receipt_counts_as_success:
        if closeout_ran == "true" or ser_ran == "true" or bm002_result == "PASS":
            return "consumer_drift", "non-success root receipt conflicts with downstream success"
        if downstream_present:
            return "aligned_non_success_root", "non-success root receipt agrees with downstream non-success"
        return "non_success_root_without_downstream", "non-success root receipt with no downstream surface"

    if closeout_ran == "true" or ser_ran == "true" or bm002_result == "PASS":
        return "consumer_drift", "downstream success without root receipt"
    if downstream_present:
        return "aligned_no_root", "no root receipt and downstream surfaces agree critique did not run"
    return "no_root_no_downstream", "no root receipt and no downstream surfaces"


